// GetStockTree returns a paginated forest of RepositoryTree roots with current stocks.
func (r *queryResolver) GetStockTree(ctx context.Context, after *entgql.Cursor[uuid.UUID], first *int, before *entgql.Cursor[uuid.UUID], last *int, where *gen.StockWhereInput) (*model.RepositoryTreeConnection, error) {
	if where == nil {
		where = &gen.StockWhereInput{}
	}

	if where.CreatedAtLT == nil {
		now := time.Now().UTC()
		where.CreatedAtLT = &now
	}

	req := request.ForContext(ctx)

	if where.TenantID == nil {
		where.TenantIDIn = req.TenantIDs()
	}

	// Find the latest stock ID per (repository_id, item_id) matching the filters.
	stockPreds := BuildPredicates(where)
	ids, err := latestStockIDs(ctx, r.client.Stock.Query(), stockPreds...)
	if err != nil {
		return nil, err
	}

	var stocks []*gen.Stock
	if len(ids) > 0 {
		stocks, err = r.client.Stock.Query().
			Where(stock.IDIn(ids...)).
			Order(gen.Desc(stock.FieldCreatedAt)).
			AllPages(ctx, mixin.Limit)
	}
	if err != nil {
		return nil, err
	}

	stocksByRepo := make(map[uuid.UUID][]*gen.Stock)
	var stockedRepos []uuid.UUID
	for _, s := range stocks {
		if _, exists := stocksByRepo[s.RepositoryID]; !exists {
			stockedRepos = append(stockedRepos, s.RepositoryID)
		}
		stocksByRepo[s.RepositoryID] = append(stocksByRepo[s.RepositoryID], s)
	}

	repos, err := r.client.Repository.Query().
		Where(repository.TenantIDIn(req.TenantIDs()...)).
		AllPages(ctx, mixin.Limit)
	if err != nil {
		return nil, err
	}

	repoTree := make(map[uuid.UUID]*model.RepositoryTree, len(repos))
	childrenMap := make(map[uuid.UUID]bool)

	for _, repo := range repos {
		var parentID *uuid.UUID
		if repo.ParentID != uuid.Nil {
			pid := repo.ParentID
			parentID = &pid
		} else {
			parentID = nil
		}

		repoTree[repo.ID] = &model.RepositoryTree{
			RepositoryID: repo.ID,
			ParentID:     parentID,
			Stocks:       stocksByRepo[repo.ID],
			Children:     []*model.RepositoryTreeEdge{},
			CreatedAt:    repo.CreatedAt,
		}
	}

	for id, node := range repoTree {
		if node.ParentID != nil && *node.ParentID != uuid.Nil {
			if parent, ok := repoTree[*node.ParentID]; ok {
				parent.Children = append(parent.Children, &model.RepositoryTreeEdge{
					Cursor: entgql.Cursor[uuid.UUID]{ID: id},
					Node:   node,
				})
				childrenMap[id] = true
			}
		}
	}

	var roots []*model.RepositoryTree
	for id, node := range repoTree {
		if !childrenMap[id] {
			roots = append(roots, node)
		}
	}
	sort.SliceStable(roots, func(i, j int) bool { return roots[i].CreatedAt.After(roots[j].CreatedAt) })

	includeInit := map[uuid.UUID]struct{}{}
	for _, id := range stockedRepos {
		for cursorID := id; cursorID != uuid.Nil; {
			includeInit[cursorID] = struct{}{}
			if n := repoTree[cursorID]; n != nil && n.ParentID != nil {
				cursorID = *n.ParentID
			} else {
				break
			}
		}
	}

	initialTree := PruneTree(roots, includeInit)
	allEdges := FlattenTreeEdges(initialTree)

	var stockedEdges []*model.RepositoryTreeEdge
	for _, e := range allEdges {
		if len(e.Node.Stocks) > 0 {
			stockedEdges = append(stockedEdges, e)
		}
	}
	total := len(stockedEdges)

	start, end := 0, total
	if after != nil {
		for i, e := range stockedEdges {
			if e.Cursor.ID == after.ID {
				start = i + 1
				break
			}
		}
	}

	if before != nil {
		for i, e := range stockedEdges {
			if e.Cursor.ID == before.ID {
				end = i
				break
			}
		}
	}

	if first != nil && end-start > *first {
		end = start + *first
	}

	if last != nil && end-start > *last {
		start = end - *last
		if start < 0 {
			start = 0
		}
	}
	selectedEdges := stockedEdges[start:end]

	includeSelected := map[uuid.UUID]struct{}{}
	for _, e := range selectedEdges {
		for cursorID := e.Cursor.ID; cursorID != uuid.Nil; {
			includeSelected[cursorID] = struct{}{}
			if n := repoTree[cursorID]; n != nil && n.ParentID != nil {
				cursorID = *n.ParentID
			} else {
				break
			}
		}
	}
	finalTree := PruneTree(initialTree, includeSelected)

	var outEdges []*model.RepositoryTreeEdge
	if after != nil || before != nil || first != nil || last != nil {
		for _, r := range finalTree {
			outEdges = append(outEdges, &model.RepositoryTreeEdge{
				Cursor: entgql.Cursor[uuid.UUID]{ID: r.RepositoryID},
				Node:   r,
			})
		}
	} else {
		for _, r := range initialTree {
			outEdges = append(outEdges, &model.RepositoryTreeEdge{
				Cursor: entgql.Cursor[uuid.UUID]{ID: r.RepositoryID},
				Node:   r,
			})
		}
	}

	var startCursor, endCursor *entgql.Cursor[uuid.UUID]
	if len(selectedEdges) > 0 {
		startCursor = &selectedEdges[0].Cursor
		endCursor = &selectedEdges[len(selectedEdges)-1].Cursor
	}

	return &model.RepositoryTreeConnection{
		Edges: outEdges,
		PageInfo: &entgql.PageInfo[uuid.UUID]{
			StartCursor:     startCursor,
			EndCursor:       endCursor,
			HasNextPage:     end < total,
			HasPreviousPage: start > 0,
		},
	}, nil
}

// Time is the resolver for the time field.
func (r *stockWhereInputResolver) Time(ctx context.Context, obj *gen.StockWhereInput, data *time.Time) error {
	if data == nil {
		t := time.Now().UTC()
		data = &t
	}

	// Set CreatedAtLT so GetStockTree (which uses BuildPredicates) can use the
	// time cutoff in its own latest-per-group logic.
	obj.CreatedAtLT = data

	req := request.ForContext(ctx)
	tenantIDs := req.TenantIDs()
	if len(tenantIDs) == 0 {
		return nil
	}

	// For the regular stocks query (which doesn't do its own dedup),
	// pre-compute the latest stock IDs per (repository_id, item_id) before
	// the cutoff time and add as a predicate.
	timePreds := []predicate.Stock{stock.CreatedAtLT(*data), stock.TenantIDIn(tenantIDs...)}
	ids, err := latestStockIDs(ctx, r.client.Stock.Query(), timePreds...)
	if err != nil {
		return err
	}

	if len(ids) == 0 {
		obj.AddPredicates(stock.IDEQ(uuid.Nil))
	} else {
		obj.AddPredicates(stock.IDIn(ids...))
	}

	return nil
}

// NetStockGte is the resolver for the netStockGTE field.
func (r *stockWhereInputResolver) NetStockGte(ctx context.Context, obj *gen.StockWhereInput, data *int) error {
	if obj == nil || data == nil {
		return nil
	}

	obj.AddPredicates(func(s *sql.Selector) {
		expr := fmt.Sprintf("(%s + %s - %s)",
			s.C(stock.FieldOwnQuantity),
			s.C(stock.FieldOwnIncomingStock),
			s.C(stock.FieldOwnOutgoingStock),
		)
		s.Where(sqljson.ValueGTE(expr, *data))
	})

	return nil
}
